#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[300001], F[300001];
        scanf("%s %s", S, F);
        int n = strlen(S), m = strlen(F);
        long long dp[n + 1] = {0};
        for (int i = m; i <= n; i++) {
            if (strncmp(S + i - m, F, m) == 0) {
                dp[i] = (dp[i] + 1) % MOD;
                for (int j = i - m; j >= 0; j--) {
                    dp[i] = (dp[i] + dp[j]) % MOD;
                }
            } else {
                dp[i] = dp[i - 1];
            }
        }
        printf("%lld\n", dp[n]);
    }
    return 0;
}

